#include <stdio.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X; scanf("%lld", &X);
        long long msb = 1LL << (63 - __builtin_clzll(X)); // highest power of two <= X
        long long A = X - msb;
        long long B = msb;
        printf("%lld %lld\n", A, B);
    }
    return 0;
}

